					fallbackEmptyIdx = i
				}
				continue
			}
			assignCopy := dispatch.Assigns[i]
			oldCost := assignCopy.Cost
			if !assignCopy.AddShip(shipID, ori, des) {
				continue
			}
			assignCopy.GenRoute()
			newCost := assignCopy.Cost
			if newCost >= 0 {
				delta := newCost - oldCost
				timeTightWeight := 1.0
				if ori.TimeStart > 0 && ori.TimeEnd > ori.TimeStart {
