		des := dess[shipIdx]
		loadSum := ori.Load + des.Load

		timeSlackOri := ori.TimeEnd - ori.TimeStart
		if timeSlackOri <= 0 {
			timeSlackOri = 1
		}
		timeSlackDes := des.TimeEnd - des.TimeStart
		if timeSlackDes <= 0 {
			timeSlackDes = 1
		}
		slackWeight := float64(timeSlackOri*timeSlackDes) / 10000.0
		if slackWeight < 0.5 {
			slackWeight = 0.5
		} else if slackWeight > 2.0 {
			slackWeight = 2.0
		}

		for i := 0; i < dispatch.AssignsLen; i++ {
			assignCopy := dispatch.Assigns[i]
			oldCost := assignCopy.Cost
			success := assignCopy.AddShip(total_ship+shipIdx, ori, des)
			if success {
				assignCopy.GenRoute()
				newCost := assignCopy.Cost
				if newCost >= 0 {
					marginalCost := newCost - oldCost
					distanceFactor := cal_dis(assignCopy.StationCurrent, ori) + cal_dis(ori, des)
					if distanceFactor <= 0 {
						distanceFactor = 1.0
					}
					score := (marginalCost / distanceFactor) * slackWeight / (float64(loadSum)/10.0 + 1.0)

					tieBreak := 0.0
					if score == bestScore {
						tieBreak = float64(i%3) * 0.001
					}
					score += tieBreak

					if score < bestScore {
						bestScore = score
						bestAssignIdx = i
					}
				}
